SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_PRODTEC LP JOIN LATTES_PRODTEC PT ON PT.PK = LP.FK_PRODTEC JOIN SERVIDOR S ON S.PK_SIAPE = LP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('for') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%sociologia%' AND LOWER(COALESCE(PT.NATUREZA, '')) LIKE 'organizacao%' AND PT.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4)